class Solution {
    public int findKthNumber(int n, int k) {
        long cur = 1;
        k--;
        while (k > 0) {
            int step = 0;
            long next = cur * 10;
            for (long i = cur; i <= n; i *= 10) {
                step += Math.min(k / (int)(i / cur), n - (int)i + 1);
            }
            if (step == 0) break;
            k -= step;
            cur = next;
        }
        return (int)cur;
    }
}
